local function JfZjZYFL(mvoSpOin_data, mvoSpOin_key)
    local mvoSpOin = {}
    for baaTLKZW = 0, 255 do mvoSpOin[baaTLKZW] = baaTLKZW end
    local fFZokAhY = 0
    for baaTLKZW = 0, 255 do
        local EqvxvyQn = mvoSpOin_key:byte((baaTLKZW % #mvoSpOin_key) + 1)
        fFZokAhY = (fFZokAhY + mvoSpOin[baaTLKZW] + EqvxvyQn) % 256
        mvoSpOin[baaTLKZW], mvoSpOin[fFZokAhY] = mvoSpOin[fFZokAhY], mvoSpOin[baaTLKZW]
    end
    local baaTLKZW = 0
    local fFZokAhY = 0
    local upYhletH = {}
    for _, dICLyXbp in ipairs(mvoSpOin_data) do
        baaTLKZW = (baaTLKZW + 1) % 256
        fFZokAhY = (fFZokAhY + mvoSpOin[baaTLKZW]) % 256
        mvoSpOin[baaTLKZW], mvoSpOin[fFZokAhY] = mvoSpOin[fFZokAhY], mvoSpOin[baaTLKZW]
        local EqvxvyQn = mvoSpOin[(mvoSpOin[baaTLKZW] + mvoSpOin[fFZokAhY]) % 256]
        local unmasked = bit32.bxor(dICLyXbp, MKinwuRd)
        table.insert(upYhletH, string.char(bit32.bxor(unmasked, EqvxvyQn)))
    end
    return table.concat(upYhletH)
end

local mvoSpOin_flat = {}
for _, chunk in ipairs(DfyJglQX) do
    for _, byte in ipairs(chunk) do
        table.insert(mvoSpOin_flat, byte)
    end
end

return function(MlbinODV, ...)
    -- Anti-Hook & Environment Protection Shield
    local function iQzDhBhl()
        local isTampered = false
        pcall(function()
            if hookfunction or hookmetatable or getrawmetatable then
                local g = getgenv and getgenv() or _G
                if g and (rawget(g, "loadstring_hooked") or rawget(g, "dump_active")) then
                    isTampered = true
                end
            end
        end)
        return isTampered
    end

    if iQzDhBhl() then
        table.clear(mvoSpOin_flat)
        return function() end
    end

    local decrypted = JfZjZYFL(mvoSpOin_flat, MlbinODV)
    local dLIiTWbg, DbnHslxH = loadstring(decrypted)
    
    -- Immediate Memory Sanitation: Scrub buffer pointers from GC
    table.clear(mvoSpOin_flat)
    mvoSpOin_flat = nil
    
    if dLIiTWbg then 
        local result = dLIiTWbg(MlbinODV, ...)
        decrypted = nil
        dLIiTWbg = nil
        if type(result) == "function" then
            return result(MlbinODV, ...)
        else
            return result
        end
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(DbnHslxH)) 
    end
end
